#include <bits/stdc++.h>
using namespace std;
map<string,vector<int> >mmap;
int main()
{
    int n,m;
    cin>>n;
    for(int i=0;i<n;i++)
    {
        int k;
        cin>>k;
        for(int j=0;j<k;j++)
        {
            string s;
            cin>>s;
            mmap[s].push_back(i+1);
        }
    }
    cin>>m;
    for(int i=0;i<m;i++)
    {
        string s;
        cin>>s;
        bool mark[1005]={};
        for(int j=0;j<mmap[s].size();j++)
        {
            if(mark[mmap[s][j]]==false)
            {
                cout<<mmap[s][j]<<" ";
                mark[mmap[s][j]]=true;
            }
        }
        cout<<endl;
    }
    return 0;
}
